159	        dot_str += "}\n";
160	        return dot_str;
161	    }
162	
163	    void debug_audit() const override
164	    {
165	#ifdef UHD_EXPERT_LOGGING
166	        EX_LOG(0, "debug_audit()");
167	
168	        // Test 1: Check for cycles in graph
169	        std::vector<std::string> back_edges;
170	        cycle_det_visitor cdet_vis(back_edges);
171	        boost::depth_first_search(_expert_dag, boost::visitor(cdet_vis));
172	        if (back_edges.empty()) {
173	            EX_LOG(1, "cycle check ... PASSED");
174	        } else {
175	            EX_LOG(1, "cycle check ... ERROR!!!");
176	            for (const std::string& e : back_edges) {
177	                EX_LOG(2, "back edge: " + e);
178	            }
179	        }
180	        back_edges.clear();
181	
182	        // Test 2: Check data node input and output edges
183	        std::vector<std::string> data_node_issues;
184	        for (const vertex_map_t::value_type& v : _datanode_map) {
185	            size_t in_count = 0, out_count = 0;
186	            for (std::pair<edge_iter, edge_iter> ei = boost::edges(_expert_dag);
187	                 ei.first != ei.second;
188	                 ++ei.first) {
189	                if (boost::target(*(ei.first), _expert_dag) == v.second)
190	                    in_count++;
191	                if (boost::source(*(ei.first), _expert_dag) == v.second)
192	                    out_count++;
193	            }
194	            bool prop_unused = false;
195	            if (in_count > 1) {
196	                data_node_issues.push_back(v.first + ": multiple writers (workers)");
197	            } else if (in_count > 0) {
198	                if (_expert_dag[v.second]->get_class() == CLASS_PROPERTY) {
199	                    data_node_issues.push_back(
200	                        v.first + ": multiple writers (worker and property tree)");
201	                }
202	            } else {
203	                if (_expert_dag[v.second]->get_class() != CLASS_PROPERTY) {
204	                    data_node_issues.push_back(
205	                        v.first + ": unreachable (will always hold initial value)");
206	                } else if (_expert_dag[v.second]->get_class() == CLASS_PROPERTY
207	                           and not _expert_dag[v.second]->has_write_callback()) {
208	                    if (out_count > 0) {
209	                        data_node_issues.push_back(
210	                            v.first + ": needs explicit resolve after write");
211	                    } else {
212	                        data_node_issues.push_back(
213	                            v.first + ": unused (no readers or writers)");
214	                        prop_unused = true;
215	                    }
216	                }
217	            }
218	            if (out_count < 1) {
219	                if (_expert_dag[v.second]->get_class() != CLASS_PROPERTY) {
220	                    data_node_issues.push_back(
221	                        v.first + ": unused (is not read by any worker)");
222	                } else if (_expert_dag[v.second]->get_class() == CLASS_PROPERTY
223	                           and not _expert_dag[v.second]->has_read_callback()) {
224	                    if (not prop_unused) {
225	                        data_node_issues.push_back(
226	                            v.first + ": needs explicit resolve to read");
227	                    }
228	                }
229	            }
230	        }
231	
232	        if (data_node_issues.empty()) {
233	            EX_LOG(1, "data node check ... PASSED");
234	        } else {
235	            EX_LOG(1, "data node check ... WARNING!");
236	            for (const std::string& i : data_node_issues) {
237	                EX_LOG(2, i);
238	            }
239	        }
240	        data_node_issues.clear();
241	
242	        // Test 3: Check worker node input and output edges
243	        std::vector<std::string> worker_issues;
244	        for (const vertex_map_t::value_type& v : _worker_map) {
245	            size_t in_count = 0, out_count = 0;
246	            for (std::pair<edge_iter, edge_iter> ei = boost::edges(_expert_dag);
247	                 ei.first != ei.second;
248	                 ++ei.first) {
249	                if (boost::target(*(ei.first), _expert_dag) == v.second)
250	                    in_count++;
251	                if (boost::source(*(ei.first), _expert_dag) == v.second)
252	                    out_count++;
253	            }
254	            if (in_count < 1) {
255	                worker_issues.push_back(v.first + ": no inputs (will never resolve)");
256	            }
257	            if (out_count < 1) {
258	                worker_issues.push_back(v.first + ": no outputs");
259	            }
260	        }
261	        if (worker_issues.empty()) {
262	            EX_LOG(1, "worker check ... PASSED");
263	        } else {
264	            EX_LOG(1, "worker check ... WARNING!");
265	            for (const std::string& i : worker_issues) {
266	                EX_LOG(2, i);
267	            }
268	        }
269	        worker_issues.clear();
270	#endif
271	    }
272	
273	    inline std::recursive_mutex& resolve_mutex() override
274	    {
275	        return _resolve_mutex;
276	    }
277	
278	protected:
279	    void add_data_node(dag_vertex_t* data_node, auto_resolve_mode_t resolve_mode) override
280	    {
281	        std::lock_guard<std::mutex> lock(_mutex);
282	
283	        // Sanity check node pointer
284	        if (data_node == NULL) {
285	            throw uhd::runtime_error(
286	                "NULL data node passed into expert container for registration.");
287	        }
288	
289	        // Sanity check the data node and ensure that it is not already in this graph
290	        EX_LOG(0, str(boost::format("add_data_node(%s)") % data_node->get_name()));
291	        if (data_node->get_class() == CLASS_WORKER) {
292	            throw uhd::runtime_error("Supplied node " + data_node->get_name()
293	                                     + " is not a data/property node.");
294	            // Throw leaves data_node undeleted
295	        }
296	        if (_datanode_map.find(data_node->get_name()) != _datanode_map.end()) {
297	            throw uhd::runtime_error(
298	                "Data node with name " + data_node->get_name() + " already exists");
299	            // Throw leaves data node undeleted
300	        }
301	
302	        try {
303	            // Add a vertex in this graph for the data node
304	            expert_graph_t::vertex_descriptor gr_node =
305	                boost::add_vertex(data_node, _expert_dag);
306	            EX_LOG(1, str(boost::format("added vertex %s") % data_node->get_name()));
307	            _datanode_map.insert(
308	                vertex_map_t::value_type(data_node->get_name(), gr_node));
309	
310	            // Add resolve callbacks
311	            if (resolve_mode == AUTO_RESOLVE_ON_WRITE
312	                or resolve_mode == AUTO_RESOLVE_ON_READ_WRITE) {
313	                EX_LOG(2, str(boost::format("added write callback")));
314	                data_node->set_write_callback(std::bind(
315	                    &expert_container_impl::resolve_from, this, std::placeholders::_1));
316	            }
317	            if (resolve_mode == AUTO_RESOLVE_ON_READ
318	                or resolve_mode == AUTO_RESOLVE_ON_READ_WRITE) {
319	                EX_LOG(2, str(boost::format("added read callback")));
320	                data_node->set_read_callback(std::bind(
321	                    &expert_container_impl::resolve_to, this, std::placeholders::_1));
322	            }
323	        } catch (...) {
324	            clear();
325	            throw uhd::assertion_error("Unknown unrecoverable error adding data node. "
326	                                       "Cleared expert container.");
327	        }
328	    }
329	
330	    void add_worker(worker_node_t* worker) override
331	    {
332	        std::lock_guard<std::mutex> lock(_mutex);
333	
334	        // Sanity check node pointer
335	        if (worker == NULL) {
336	            throw uhd::runtime_error(
337	                "NULL worker passed into expert container for registration.");
338	        }
339	
340	        // Sanity check the data node and ensure that it is not already in this graph
341	        EX_LOG(0, str(boost::format("add_worker(%s)") % worker->get_name()));
342	        if (worker->get_class() != CLASS_WORKER) {
343	            throw uhd::runtime_error(
344	                "Supplied node " + worker->get_name() + " is not a worker node.");
345	        }
346	        if (_worker_map.find(worker->get_name()) != _worker_map.end()) {
347	            throw uhd::runtime_error(
348	                "Resolver with name " + worker->get_name() + " already exists.");
349	        }
350	
351	        try {
352	            // Add a vertex in this graph for the worker node
353	            expert_graph_t::vertex_descriptor gr_node =
354	                boost::add_vertex(worker, _expert_dag);
355	            EX_LOG(1, str(boost::format("added vertex %s") % worker->get_name()));
356	            _worker_map.insert(vertex_map_t::value_type(worker->get_name(), gr_node));
357	
358	            // For each input, add an edge from the input to this node
359	            for (const std::string& node_name : worker->get_inputs()) {
360	                vertex_map_t::const_iterator node = _datanode_map.find(node_name);
361	                if (node != _datanode_map.end()) {
362	                    boost::add_edge((*node).second, gr_node, _expert_dag);
363	                    EX_LOG(1,
364	                        str(boost::format("added edge %s->%s")
365	                            % _expert_dag[(*node).second]->get_name()
366	                            % _expert_dag[gr_node]->get_name()));
367	                } else {
368	                    throw uhd::runtime_error(
369	                        "Data node with name " + node_name + " was not found");
370	                }
371	            }
372	
373	            // For each output, add an edge from this node to the output
374	            for (const std::string& node_name : worker->get_outputs()) {
375	                vertex_map_t::const_iterator node = _datanode_map.find(node_name);
376	                if (node != _datanode_map.end()) {
377	                    boost::add_edge(gr_node, (*node).second, _expert_dag);
378	                    EX_LOG(1,
379	                        str(boost::format("added edge %s->%s")
380	                            % _expert_dag[gr_node]->get_name()
381	                            % _expert_dag[(*node).second]->get_name()));
382	                } else {
383	                    throw uhd::runtime_error(
384	                        "Data node with name " + node_name + " was not found");
385	                }
386	            }
387	        } catch (uhd::runtime_error& ex) {
388	            clear();
389	            // Promote runtime_error to assertion_error
390	            throw uhd::assertion_error(
391	                std::string(ex.what())
392	                + " (Cleared expert container because error is unrecoverable).");
393	        } catch (...) {
394	            clear();
395	            throw uhd::assertion_error(
396	                "Unknown unrecoverable error adding worker. Cleared expert container.");
397	        }
398	    }
399	
400	    void clear() override
401	    {
402	        std::lock_guard<std::mutex> lock(_mutex);
403	        EX_LOG(0, "clear()");
404	
405	        // Iterate through the vertices and release their node storage
406	        typedef boost::graph_traits<expert_graph_t>::vertex_iterator vertex_iter;
407	        for (std::pair<vertex_iter, vertex_iter> vi = boost::vertices(_expert_dag);
408	             vi.first != vi.second;
409	             ++vi.first) {
410	            try {
411	                delete _expert_dag[*vi.first];
412	                _expert_dag[*vi.first] = NULL;
413	            } catch (...) {
414	                // If a dag_vertex is a worker, it has a virtual dtor which
415	                // can possibly throw an exception. We will not let that
416	                // terminate clear() and leave things in a bad state.
417	            }
418	        }
419	
420	        // The following calls will not throw because they all contain
421	        // intrinsic types.
422	
423	        // Release all vertices and edges in the DAG
424	        _expert_dag.clear();
425	
426	        // Release all nodes in the map
427	        _worker_map.clear();
428	        _datanode_map.clear();
429	    }
430	
431	private:
432	    void _resolve_helper(std::string start, std::string stop, bool force)
433	    {
434	        // Sort the graph topologically. This ensures that for all dependencies, the
435	        // dependant is always after all of its dependencies.
436	        node_queue_t sorted_nodes;
437	        try {
438	            boost::topological_sort(_expert_dag, std::front_inserter(sorted_nodes));
439	        } catch (boost::not_a_dag&) {
440	            std::vector<std::string> back_edges;
441	            cycle_det_visitor cdet_vis(back_edges);
442	            boost::depth_first_search(_expert_dag, boost::visitor(cdet_vis));
443	            if (not back_edges.empty()) {
444	                std::string edges;
445	                for (const std::string& e : back_edges) {
446	                    edges += "* " + e + "";
447	                }
448	                throw uhd::runtime_error(
449	                    "Cannot resolve expert because it has at least one cycle!\n"
450	                    "The following back-edges were found:"
451	                    + edges);
452	            }
453	        }
454	        if (sorted_nodes.empty())
455	            return;
456	
457	        // Determine the start and stop node. If one is not explicitly specified then
458	        // resolve everything
459	        expert_graph_t::vertex_descriptor start_vertex = sorted_nodes.front();
460	        expert_graph_t::vertex_descriptor stop_vertex  = sorted_nodes.back();
461	        if (not start.empty())
462	            start_vertex = _lookup_vertex(start);
463	        if (not stop.empty())
464	            stop_vertex = _lookup_vertex(stop);
465	
466	        // First Pass: Resolve all nodes if they are dirty, in a topological order
467	        std::list<dag_vertex_t*> resolved_workers;
468	        bool start_node_encountered = false;
469	        for (node_queue_t::iterator node_iter = sorted_nodes.begin();
470	             node_iter != sorted_nodes.end();
471	             ++node_iter) {
472	            // Determine if we are at or beyond the starting node
473	            if (*node_iter == start_vertex)
474	                start_node_encountered = true;
475	
476	            // Only resolve if the starting node has passed
477	            if (start_node_encountered) {
478	                dag_vertex_t& node = _get_vertex(*node_iter);
479	                std::string node_val;
480	                if (force or node.is_dirty()) {
481	                    node.resolve();
482	                    if (node.get_class() == CLASS_WORKER) {
483	                        resolved_workers.push_back(&node);
484	                    }
485	                    EX_LOG(1,
486	                        str(boost::format("resolved node %s (%s) [%s]") % node.get_name()
487	                            % (node.is_dirty() ? "dirty" : "clean") % node.to_string()));
488	                } else {
489	                    EX_LOG(1,
490	                        str(boost::format("skipped node %s (%s) [%s]") % node.get_name()
491	                            % (node.is_dirty() ? "dirty" : "clean") % node.to_string()));
492	                }
493	            }
494	
495	            // Determine if we are beyond the stop node
496	            if (*node_iter == stop_vertex)
497	                break;
498	        }
499	
500	        // Second Pass: Mark all the workers clean. The policy is that a worker will mark
501	        // all of its dependencies clean so after this step all data nodes that are not
502	        // consumed by a worker will remain dirty (as they should because no one has
503	        // consumed their value)
504	        for (std::list<dag_vertex_t*>::iterator worker = resolved_workers.begin();
505	             worker != resolved_workers.end();
506	             ++worker) {
507	            (*worker)->mark_clean();
508	        }
509	    }
510	
511	    expert_graph_t::vertex_descriptor _lookup_vertex(const std::string& name) const
512	    {
513	        expert_graph_t::vertex_descriptor vertex;
514	        // Look for node in the data-node map
515	        vertex_map_t::const_iterator vertex_iter = _datanode_map.find(name);
516	        if (vertex_iter != _datanode_map.end()) {
517	            vertex = (*vertex_iter).second;
518	        } else {
519	            // If not found, look in the worker-node map
520	            vertex_iter = _worker_map.find(name);
521	            if (vertex_iter != _worker_map.end()) {
522	                vertex = (*vertex_iter).second;
523	            } else {
524	                throw uhd::lookup_error("Could not find node with name " + name);
525	            }
526	        }
527	        return vertex;
528	    }
529	
530	    dag_vertex_t& _get_vertex(expert_graph_t::vertex_descriptor desc) const
531	    {
532	        // Requirement: Node must exist in expert graph
533	        dag_vertex_t* vertex_ptr = _expert_dag[desc];
534	        if (vertex_ptr) {
535	            return *vertex_ptr;
536	        } else {
537	            throw uhd::assertion_error("Expert graph malformed. Found a NULL node.");
538	        }
539	    }
540	
541	    void _log(size_t depth, const std::string& str) const
542	    {
543	        std::string indents;
544	        for (size_t i = 0; i < depth; i++)
545	            indents += "- ";
546	        UHD_LOG_DEBUG("EXPERT", "[expert::" + _name + "] " << indents << str)
547	    }
548	
549	private:
550	    const std::string _name;
551	    expert_graph_t _expert_dag; // The primary graph data structure as an adjacency list
552	    vertex_map_t _worker_map; // A map from vertex name to vertex descriptor for workers
553	    vertex_map_t
554	        _datanode_map; // A map from vertex name to vertex descriptor for data nodes
555	    std::mutex _mutex;
556	    std::recursive_mutex _resolve_mutex;
557	};
558	
559	expert_container::sptr expert_container::make(const std::string& name)
560	{
561	    return std::make_shared<expert_container_impl>(name);
562	}
563	
564	}} // namespace uhd::experts
