205	        *(const_cast<data_node_t<int>*>(dynamic_cast<const data_node_t<int>*>(
206	            &container->node_retriever().lookup("A/desired"))));
207	    data_node_t<int>& nodeB = *(const_cast<data_node_t<int>*>(
208	        dynamic_cast<const data_node_t<int>*>(&container->node_retriever().lookup("B"))));
209	    data_node_t<int>& nodeC = *(const_cast<data_node_t<int>*>(
