17	using namespace uhd;
18	
19	namespace uhd { namespace usrp { namespace zbx {
20	
21	namespace {
22	
23	/*********************************************************************
24	 *   Misc/calculative helper functions
25	 **********************************************************************/
26	bool _is_band_highband(const zbx_tune_map_item_t tune_setting)
27	{
28	    // Lowband frequency paths do not utilize an RF filter
29	    return tune_setting.rf_fltr == 0;
30	}
31	
32	zbx_tune_map_item_t _get_tune_settings(
33	    const double freq, const std::vector<zbx_tune_map_item_t>& tune_map)
34	{
35	    auto tune_setting      = tune_map.begin();
36	    auto tune_settings_end = tune_map.end();
37	
38	    for (; tune_setting != tune_settings_end; ++tune_setting) {
39	        if (tune_setting->max_band_freq >= freq) {
40	            return *tune_setting;
41	        }
42	    }
43	    // Didn't find a tune setting.  This frequency should have been clipped, this is
44	    // an internal error.
45	    UHD_THROW_INVALID_CODE_PATH();
46	}
47	
48	bool _is_band_inverted(const uhd::direction_t trx,
49	    const double if2_freq,
50	    const double rfdc_rate,
51	    const zbx_tune_map_item_t tune_setting)
52	{
53	    const bool is_if2_nyquist2 = if2_freq > (rfdc_rate / 2);
54	
55	    // We count the number of inversions introduced by the signal chain, starting
56	    // at the RFDC
57	    const int num_inversions =
58	        // If we're in the second Nyquist zone, we're inverted
59	        int(is_if2_nyquist2) +
60	        // LO2 mixer may invert
61	        int(tune_setting.lo2_inj_side == HIGH) +
62	        // LO1 mixer can only invert in the lowband
63	        int(!_is_band_highband(tune_setting) && tune_setting.lo1_inj_side == HIGH);
64	
65	    // In the RX direction, an extra inversion is needed
66	    // TODO: We don't know where this is coming from
67	    const bool num_inversions_is_odd = num_inversions % 2 != 0;
68	    if (trx == RX_DIRECTION) {
69	        return !num_inversions_is_odd;
70	    } else {
71	        return num_inversions_is_odd;
72	    }
73	}
74	
75	double _calc_lo2_freq(
76	    const double if1_freq, const double if2_freq, const lo_inj_side_t lo2_inj_side)
77	{
78	    return if1_freq - static_cast<double>(lo2_inj_side) * if2_freq;
79	}
80	
81	double _calc_if2_freq(const double if1_freq, const double lo2_freq)
82	{
83	    return std::abs(if1_freq - lo2_freq);
84	}
85	
86	std::string _get_trx_string(const direction_t dir)
87	{
88	    if (dir == RX_DIRECTION) {
89	        return "rx";
90	    } else if (dir == TX_DIRECTION) {
91	        return "tx";
92	    } else {
93	        UHD_THROW_INVALID_CODE_PATH();
94	    }
95	}
96	
97	// For various RF performance considerations (such as spur reduction), different bands
98	// vary between using fixed IF1 and/or IF2 or using variable IF1 and/or IF2. Bands
99	// with a fixed IF1/IF2 have ifX_freq_min == IFX_freq_max, and _calc_ifX_freq() will
100	// return that single value. Bands with variable IF1/IF2 will shift the IFX based on
101	// where in the RF band we are tuning by using linear interpolation. (if1 calculation
102	// takes place only if tune frequency is lowband)
103	double _calc_if1_freq(const double tune_freq, const zbx_tune_map_item_t tune_setting)
104	{
105	    if (tune_setting.if1_freq_min == tune_setting.if1_freq_max) {
106	        return tune_setting.if1_freq_min;
107	    }
108	
109	    return uhd::math::linear_interp(tune_freq,
110	        tune_setting.min_band_freq,
111	        tune_setting.if1_freq_min,
112	        tune_setting.max_band_freq,
113	        tune_setting.if1_freq_max);
114	}
115	
116	double _calc_ideal_if2_freq(
117	    const double tune_freq, const zbx_tune_map_item_t tune_setting)
118	{
119	    // linear_interp() wants to interpolate and will throw if these are identical:
120	    if (tune_setting.if2_freq_min == tune_setting.if2_freq_max) {
121	        return tune_setting.if2_freq_min;
122	    }
123	
124	    return uhd::math::linear_interp(tune_freq,
125	        tune_setting.min_band_freq,
126	        tune_setting.if2_freq_min,
127	        tune_setting.max_band_freq,
128	        tune_setting.if2_freq_max);
129	}
130	
131	} // namespace
132	
133	/*!---------------------------------------------------------
134	 * EXPERT RESOLVE FUNCTIONS
135	 *
136	 * This sections contains all expert resolve functions.
137	 * These methods are triggered by any of the bound accessors becoming "dirty",
138	 * or changing value
139	 * --------------------------------------------------------
140	 */
141	void zbx_scheduling_expert::resolve()
142	{
143	    // We currently have no fancy scheduling, but here is where we'd add it if
144	    // we need to do that (e.g., plan out SYNC pulse timing vs. NCO timing etc.)
145	    _frontend_time = _command_time;
146	}
147	
148	void zbx_freq_fe_expert::resolve()
149	{
150	    const double tune_freq = ZBX_FREQ_RANGE.clip(_desired_frequency);
151	    _tune_settings         = _get_tune_settings(tune_freq, _tune_table.get());
152	
153	    // Set mixer values so the backend expert knows how to calculate final frequency
154	    _lo1_inj_side = _tune_settings.lo1_inj_side;
155	    _lo2_inj_side = _tune_settings.lo2_inj_side;
156	
157	    _is_highband = _is_band_highband(_tune_settings);
158	    _lo1_enabled = !_is_highband.get();
159	
160	    double if1_freq      = tune_freq;
161	    const double lo_step = _lo_freq_range.step();
162	    // If we need to apply an offset to avoid injection locking, we need to
163	    // offset in different directions for different channels on the same zbx
164	    const double lo_offset_sign = (_chan == 0) ? -1 : 1;
165	    // In high band, LO1 is not needed (the signal is already at a high enough
166	    // frequency for the second stage)
167	    if (_lo1_enabled) {
168	        // Calculate the ideal IF1:
169	        if1_freq = _calc_if1_freq(tune_freq, _tune_settings);
170	        // We calculate the LO1 frequency by first shifting the tune frequency to the
171	        // desired IF, and then applying an offset such that CH0 and CH1 tune to distinct
172	        // LO1 frequencies: This is done to prevent the LO's from interfering with each
173	        // other in a phenomenon known as injection locking.
174	        const double lo1_freq =
175	            if1_freq - (static_cast<double>(_tune_settings.lo1_inj_side) * tune_freq)
176	            + (lo_offset_sign * lo_step);
177	        // Now, quantize the LO frequency to the nearest valid value:
178	        _desired_lo1_frequency = _lo_freq_range.clip(lo1_freq, true);
179	        // Because LO1 frequency probably changed during quantization, we simply
180	        // re-calculate the now-valid IF1 (the following equation is the same as
181	        // the LO1 frequency calculation, but solved for if1_freq):
182	        if1_freq = _desired_lo1_frequency
183	                   + static_cast<double>(_tune_settings.lo1_inj_side) * tune_freq;
184	    }
185	
186	    _lo2_enabled = true;
187	    // Calculate ideal IF2 frequency:
188	    const double if2_freq = _calc_ideal_if2_freq(tune_freq, _tune_settings);
189	    // Calculate LO2 frequency from that:
190	    _desired_lo2_frequency = _calc_lo2_freq(if1_freq, if2_freq, _lo2_inj_side);
191	    // Similar to LO1, apply an offset such that CH0 and CH1 tune to distinct LO2
192	    // frequencies to prevent potential interference between CH0 and CH1 LO2's from
193	    // injection locking: In highband (LO1 disabled), this must explicitly be done below.
194	    // In lowband (LO1 enabled), the LO1 will have already been shifted and, as a result,
195	    // the LO2's will have already been shifted to compensate for LO1 in previous
196	    // function. Note that in lowband, the LO1's and LO2's will be offset between CH0 and
197	    // CH1; however, they will be offset in opposite direction such that the NCO frequency
198	    // will be the same between CH0 and CH1. This is not the case for highband (only LO2
199	    // and they must be offset).
200	    if (!_lo1_enabled) {
201	        _desired_lo2_frequency = _desired_lo2_frequency + (lo_offset_sign * lo_step);
202	    }
203	    // Now, quantize the LO frequency to the nearest valid value:
204	    _desired_lo2_frequency = _lo_freq_range.clip(_desired_lo2_frequency, true);
205	    // Calculate actual IF2 frequency from LO2 and IF1 frequencies:
206	    _desired_if2_frequency = _calc_if2_freq(if1_freq, _desired_lo2_frequency);
207	
208	    // If the frequency is in a different tuning band, we need to switch filters
209	    _rf_filter  = _tune_settings.rf_fltr;
210	    _if1_filter = _tune_settings.if1_fltr;
211	    _if2_filter = _tune_settings.if2_fltr;
212	    _band_inverted =
213	        _is_band_inverted(_trx, _desired_if2_frequency, _rfdc_rate, _tune_settings);
214	}
