217	void zbx_freq_be_expert::resolve()
218	{
219	    const double coerced_if1_freq =
220	        _coerced_lo2_frequency
221	        + _coerced_if2_frequency * static_cast<double>(_lo2_inj_side);
222	    if (_is_highband) {
223	        _coerced_frequency = coerced_if1_freq;
224	    } else {
225	        _coerced_frequency = std::abs(coerced_if1_freq - _coerced_lo1_frequency);
226	    }
227	
228	    // Users may change individual settings (LO frequencies, if2 frequencies) and throw
229	    // the output frequency out of range. We have to stop here so that the gain API
230	    // doesn't panic (Clipping here would have no effect on the actual output signal)
231	    using namespace uhd::math::fp_compare;
232	    if (fp_compare_delta<double>(_coerced_frequency.get()) < ZBX_MIN_FREQ
233	        || fp_compare_delta<double>(_coerced_frequency.get()) > ZBX_MAX_FREQ) {
234	        UHD_LOG_WARNING(get_name(),
235	            "Resulting coerced frequency " << _coerced_frequency.get()
236	                                           << " is out of range!");
237	    }
238	}
