262	void zbx_tx_gain_expert::resolve()
263	{
264	    if (_profile != ZBX_GAIN_PROFILE_DEFAULT) {
265	        return;
266	    }
267	
268	    // If a user passes in a gain value, we have to set the Power API tracking mode
269	    if (_gain_in.is_dirty()) {
270	        _power_mgr->set_tracking_mode(uhd::usrp::pwr_cal_mgr::tracking_mode::TRACK_GAIN);
271	    }
272	
273	    // Now we do the overall gain setting
274	    // Look up DSA values by gain
275	    _gain_out             = ZBX_TX_GAIN_RANGE.clip(_gain_in, true);
276	    const size_t gain_idx = _gain_out / TX_GAIN_STEP;
277	    // Clip _frequency to valid ZBX range to avoid errors in the scenario when user
278	    // manually configures LO frequencies and causes an illegal overall frequency
279	    auto dsa_settings =
280	        _dsa_cal->get_dsa_setting(ZBX_FREQ_RANGE.clip(_frequency), gain_idx);
281	    // Now write to downstream nodes, converting attenuations to gains:
282	    _dsa1 = static_cast<double>(ZBX_TX_DSA_MAX_ATT - dsa_settings[0]);
283	    _dsa2 = static_cast<double>(ZBX_TX_DSA_MAX_ATT - dsa_settings[1]);
284	    // Convert amp index to gain
285	    _amp_gain = ZBX_TX_AMP_GAIN_MAP.at(static_cast<tx_amp>(dsa_settings[2]));
286	}
