288	void zbx_rx_gain_expert::resolve()
289	{
290	    if (_profile != ZBX_GAIN_PROFILE_DEFAULT) {
291	        return;
292	    }
293	
294	    // If a user passes in a gain value, we have to set the Power API tracking mode
295	    if (_gain_in.is_dirty()) {
296	        _power_mgr->set_tracking_mode(uhd::usrp::pwr_cal_mgr::tracking_mode::TRACK_GAIN);
297	    }
298	
299	    // Now we do the overall gain setting
300	    if (_frequency.get() <= RX_LOW_FREQ_MAX_GAIN_CUTOFF) {
301	        _gain_out = ZBX_RX_LOW_FREQ_GAIN_RANGE.clip(_gain_in, true);
302	    } else {
303	        _gain_out = ZBX_RX_GAIN_RANGE.clip(_gain_in, true);
304	    }
305	    // Now we do the overall gain setting
306	    // Look up DSA values by gain
307	    const size_t gain_idx = _gain_out / RX_GAIN_STEP;
308	    // Clip _frequency to valid ZBX range to avoid errors in the scenario when user
309	    // manually configures LO frequencies and causes an illegal overall frequency
310	    auto dsa_settings =
311	        _dsa_cal->get_dsa_setting(ZBX_FREQ_RANGE.clip(_frequency), gain_idx);
312	    // Now write to downstream nodes, converting attenuation to gains:
313	    _dsa1  = ZBX_RX_DSA_MAX_ATT - dsa_settings[0];
314	    _dsa2  = ZBX_RX_DSA_MAX_ATT - dsa_settings[1];
315	    _dsa3a = ZBX_RX_DSA_MAX_ATT - dsa_settings[2];
316	    _dsa3b = ZBX_RX_DSA_MAX_ATT - dsa_settings[3];
317	}
