319	void zbx_tx_programming_expert::resolve()
320	{
321	    if (_profile.is_dirty()) {
322	        if (_profile == ZBX_GAIN_PROFILE_DEFAULT || _profile == ZBX_GAIN_PROFILE_MANUAL
323	            || _profile == ZBX_GAIN_PROFILE_CPLD) {
324	            _cpld->set_atr_mode(_chan,
325	                zbx_cpld_ctrl::atr_mode_target::DSA,
326	                zbx_cpld_ctrl::atr_mode::CLASSIC_ATR);
327	        } else {
328	            _cpld->set_atr_mode(_chan,
329	                zbx_cpld_ctrl::atr_mode_target::DSA,
330	                zbx_cpld_ctrl::atr_mode::SW_DEFINED);
331	        }
332	    }
333	
334	    // If we're in any of the table modes, then we don't write DSA and amp values
335	    // A note on caching: The CPLD object caches state, and only pokes the CPLD
336	    // if it's changed. However, all DSAs are on the same register. That means
337	    // the DSA register changes, all DSA values written to the CPLD will come
338	    // from the input data nodes to this worker node. This can overwrite DSA
339	    // values if the cached version and the actual value on the CPLD differ.
340	    if (_profile == ZBX_GAIN_PROFILE_DEFAULT || _profile == ZBX_GAIN_PROFILE_MANUAL) {
341	        // Convert gains back to attenuation
342	        zbx_cpld_ctrl::tx_dsa_type dsa_settings = {
343	            uhd::narrow_cast<uint32_t>(ZBX_TX_DSA_MAX_ATT - _dsa1.get()),
344	            uhd::narrow_cast<uint32_t>(ZBX_TX_DSA_MAX_ATT - _dsa2.get())};
345	        _cpld->set_tx_gain_switches(_chan, ATR_ADDR_TX, dsa_settings);
346	        _cpld->set_tx_gain_switches(_chan, ATR_ADDR_XX, dsa_settings);
347	    }
348	
349	    // If frequency changed, we might have changed bands and the CPLD dsa tables need to
350	    // be reloaded
351	    // TODO: This is a major hack, and these tables should be loaded outside of the
352	    // tuning call.  This means every tuning request involves a large amount of CPLD
353	    // writes.
354	    // We only write when we aren't using a command time, otherwise all those CPLD
355	    // commands will line up in the CPLD command queue, and diminish any purpose
356	    // of timed commands in the first place
357	    // Clip _frequency to valid ZBX range to avoid errors in the scenario when user
358	    // manually configures LO frequencies and causes an illegal overall frequency
359	    if (_command_time == 0.0) {
360	        _cpld->update_tx_dsa_settings(
361	            _dsa_cal->get_band_settings(ZBX_FREQ_RANGE.clip(_frequency), 0 /*dsa1*/),
362	            _dsa_cal->get_band_settings(ZBX_FREQ_RANGE.clip(_frequency), 1 /*dsa2*/));
363	    }
364	
365	    for (const size_t idx : ATR_ADDRS) {
366	        _cpld->set_lo_source(idx,
367	            zbx_lo_ctrl::lo_string_to_enum(TX_DIRECTION, _chan, ZBX_LO1),
368	            _lo1_source);
369	        _cpld->set_lo_source(idx,
370	            zbx_lo_ctrl::lo_string_to_enum(TX_DIRECTION, _chan, ZBX_LO2),
371	            _lo2_source);
372	
373	        _cpld->set_tx_rf_filter(_chan, idx, _rf_filter);
374	        _cpld->set_tx_if1_filter(_chan, idx, _if1_filter);
375	        _cpld->set_tx_if2_filter(_chan, idx, _if2_filter);
376	    }
377	
378	    // Convert amp gain to amp index
379	    UHD_ASSERT_THROW(ZBX_TX_GAIN_AMP_MAP.count(_amp_gain.get()));
380	    const tx_amp amp = ZBX_TX_GAIN_AMP_MAP.at(_amp_gain.get());
381	    _cpld->set_tx_antenna_switches(_chan, ATR_ADDR_0X, _antenna, tx_amp::BYPASS);
382	    _cpld->set_tx_antenna_switches(_chan, ATR_ADDR_RX, _antenna, tx_amp::BYPASS);
383	    _cpld->set_tx_antenna_switches(_chan, ATR_ADDR_TX, _antenna, amp);
384	    _cpld->set_tx_antenna_switches(_chan, ATR_ADDR_XX, _antenna, amp);
385	
386	    // We do not update LEDs on switching TX antenna value by definition
387	}
