392	        if (_profile == ZBX_GAIN_PROFILE_DEFAULT || _profile == ZBX_GAIN_PROFILE_MANUAL
393	            || _profile == ZBX_GAIN_PROFILE_CPLD) {
394	            _cpld->set_atr_mode(_chan,
395	                zbx_cpld_ctrl::atr_mode_target::DSA,
396	                zbx_cpld_ctrl::atr_mode::CLASSIC_ATR);
397	        } else {
398	            _cpld->set_atr_mode(_chan,
399	                zbx_cpld_ctrl::atr_mode_target::DSA,
400	                zbx_cpld_ctrl::atr_mode::SW_DEFINED);
401	        }
402	    }
403	
404	    // If we're in any of the table modes, then we don't write DSA values
405	    // A note on caching: The CPLD object caches state, and only pokes the CPLD
406	    // if it's changed. However, all DSAs are on the same register. That means
407	    // the DSA register changes, all DSA values written to the CPLD will come
408	    // from the input data nodes to this worker node. This can overwrite DSA
409	    // values if the cached version and the actual value on the CPLD differ.
410	    if (_profile == ZBX_GAIN_PROFILE_DEFAULT || _profile == ZBX_GAIN_PROFILE_MANUAL) {
411	        zbx_cpld_ctrl::rx_dsa_type dsa_settings = {
412	            uhd::narrow_cast<uint32_t>(ZBX_RX_DSA_MAX_ATT - _dsa1.get()),
413	            uhd::narrow_cast<uint32_t>(ZBX_RX_DSA_MAX_ATT - _dsa2.get()),
414	            uhd::narrow_cast<uint32_t>(ZBX_RX_DSA_MAX_ATT - _dsa3a.get()),
415	            uhd::narrow_cast<uint32_t>(ZBX_RX_DSA_MAX_ATT - _dsa3b.get())};
416	        _cpld->set_rx_gain_switches(_chan, ATR_ADDR_RX, dsa_settings);
417	        _cpld->set_rx_gain_switches(_chan, ATR_ADDR_XX, dsa_settings);
418	    }
419	
420	
421	    // If frequency changed, we might have changed bands and the CPLD dsa tables need to
422	    // be reloaded
423	    // TODO: This is a major hack, and these tables should be loaded outside of the
424	    // tuning call.  This means every tuning request involves a large amount of CPLD
425	    // writes.
426	    // We only write when we aren't using a command time, otherwise all those CPLD
427	    // commands will line up in the CPLD command queue, and diminish any purpose
428	    // of timed commands in the first place
429	    // Clip _frequency to valid ZBX range to avoid errors in the scenario when user
430	    // manually configures LO frequencies and causes an illegal overall frequency
431	    if (_command_time == 0.0) {
432	        _cpld->update_rx_dsa_settings(
433	            _dsa_cal->get_band_settings(ZBX_FREQ_RANGE.clip(_frequency), 0 /*dsa1*/),
434	            _dsa_cal->get_band_settings(ZBX_FREQ_RANGE.clip(_frequency), 1 /*dsa2*/),
435	            _dsa_cal->get_band_settings(ZBX_FREQ_RANGE.clip(_frequency), 2 /*dsa3a*/),
436	            _dsa_cal->get_band_settings(ZBX_FREQ_RANGE.clip(_frequency), 3 /*dsa3b*/));
437	    }
438	
439	    for (const size_t idx : ATR_ADDRS) {
440	        _cpld->set_lo_source(idx,
441	            zbx_lo_ctrl::lo_string_to_enum(RX_DIRECTION, _chan, ZBX_LO1),
442	            _lo1_source);
443	        _cpld->set_lo_source(idx,
444	            zbx_lo_ctrl::lo_string_to_enum(RX_DIRECTION, _chan, ZBX_LO2),
445	            _lo2_source);
446	
447	        // If using the TX/RX terminal, only configure the ATR RX state since the
448	        // state of the switch at other times is controlled by TX
449	        if (_antenna != ANTENNA_TXRX || idx == ATR_ADDR_RX) {
450	            _cpld->set_rx_antenna_switches(_chan, idx, _antenna);
451	        }
452	
453	        _cpld->set_rx_rf_filter(_chan, idx, _rf_filter);
454	        _cpld->set_rx_if1_filter(_chan, idx, _if1_filter);
455	        _cpld->set_rx_if2_filter(_chan, idx, _if2_filter);
456	    }
457	
458	    _update_leds();
459	}
