461	void zbx_rx_programming_expert::_update_leds()
462	{
463	    if (_atr_mode != zbx_cpld_ctrl::atr_mode::CLASSIC_ATR) {
464	        return;
465	    }
466	    // We default to the RX1 LED for all RX antenna values that are not TX/RX0
467	    const bool rx_on_trx = _antenna == ANTENNA_TXRX;
468	    // clang-format off
469	    // G==Green, R==Red                RX2         TX/RX-G    TX/RX-R
470	    _cpld->set_leds(_chan, ATR_ADDR_0X, false,      false,     false);
471	    _cpld->set_leds(_chan, ATR_ADDR_RX, !rx_on_trx, rx_on_trx, false);
472	    _cpld->set_leds(_chan, ATR_ADDR_TX, false,      false,     true );
473	    _cpld->set_leds(_chan, ATR_ADDR_XX, !rx_on_trx, rx_on_trx, true );
474	    // clang-format on
