482	void zbx_rfdc_freq_expert::resolve()
483	{
484	    // Because we can configure both IF2 and the RFDC NCO frequency, these may
485	    // come into conflict. We choose IF2 over RFDC in that case. In other words
486	    // the only time we choose the desired RFDC frequency over the IF2 (when in
487	    // conflict) is when the RFDC freq was changed directly.
488	    const double desired_rfdc_freq = [&]() -> double {
489	        if (_rfdc_freq_desired.is_dirty() && !_if2_frequency_desired.is_dirty()) {
490	            return _rfdc_freq_desired;
491	        }
492	        return _if2_frequency_desired;
493	    }();
494	
495	    _rfdc_freq_coerced     = _rpcc->rfdc_set_nco_freq(_get_trx_string(_trx),
496	        _db_idx,
497	        _chan,
498	        desired_rfdc_freq,
499	        static_cast<size_t>(ZBX_CH_MODE));
500	    _if2_frequency_coerced = _rfdc_freq_coerced;
501	}
502	
503	void zbx_sync_expert::resolve()
504	{
505	    // Some local helper consts
506	    // clang-format off
507	    constexpr std::array<std::array<zbx_lo_t, 4>, 2> los{{{
508	        zbx_lo_t::RX0_LO1,
509	        zbx_lo_t::RX0_LO2,
510	        zbx_lo_t::TX0_LO1,
511	        zbx_lo_t::TX0_LO2
512	    }, {
513	        zbx_lo_t::RX1_LO1,
514	        zbx_lo_t::RX1_LO2,
515	        zbx_lo_t::TX1_LO1,
516	        zbx_lo_t::TX1_LO2
517	    }}};
518	    constexpr std::array<std::array<rfdc_control::rfdc_type, 2>, 2> ncos{{
519	        {rfdc_control::rfdc_type::RX0, rfdc_control::rfdc_type::TX0},
520	        {rfdc_control::rfdc_type::RX1, rfdc_control::rfdc_type::TX1}
521	    }};
522	    // clang-format on
523	
524	    // Now do some timing checks
525	    const std::vector<bool> chan_needs_sync = {_fe_time.at(0) != uhd::time_spec_t::ASAP,
526	        _fe_time.at(1) != uhd::time_spec_t::ASAP};
527	    // If there's no command time, no need to synchronize anything
528	    if (!chan_needs_sync[0] && !chan_needs_sync[1]) {
529	        UHD_LOG_TRACE(get_name(), "No command time: Skipping phase sync.");
530	        return;
531	    }
532	    const bool times_match = _fe_time.at(0) == _fe_time.at(1);
533	
534	    // ** Find LOs to synchronize *********************************************
535	    // Find dirty LOs which need sync'ing
536	    std::set<zbx_lo_t> los_to_sync;
537	    for (const size_t chan : ZBX_CHANNELS) {
538	        if (chan_needs_sync[chan]) {
539	            for (const auto& lo_idx : los[chan]) {
540	                if (_lo_freqs.at(lo_idx).is_dirty()) {
541	                    los_to_sync.insert(lo_idx);
542	                }
543	            }
544	        }
545	    }
546	
547	    // ** Find NCOs to synchronize ********************************************
548	    // Same rules apply as for LOs.
549	    std::set<rfdc_control::rfdc_type> ncos_to_sync;
550	    for (const size_t chan : ZBX_CHANNELS) {
551	        if (chan_needs_sync[chan]) {
552	            for (const auto& nco_idx : ncos[chan]) {
553	                if (_nco_freqs.at(nco_idx).is_dirty()) {
554	                    ncos_to_sync.insert(nco_idx);
555	                }
556	            }
557	        }
558	    }
559	
560	    // ** Find ADC/DAC gearboxes to synchronize *******************************
561	    // Gearboxes are special, because they only need to be synchronized once
562	    // per session, assuming the command time has been set. Unfortunately we
563	    // have no way here to know if the timekeeper time was updated, but it is
564	    // well documented that in order to synchronize devices, one first has to
565	    // make sure the timekeepers are running in sync (by calling
566	    // set_time_next_pps() accordingly).
567	    // The logic we use here is that we will always have to update the NCO when
568	    // doing a synced tune, so we update all the gearboxes for the NCOs -- but
569	    // only if they have not yet been synchronized.
570	    std::set<rfdc_control::rfdc_type> gearboxes_to_sync;
571	    if (!_adcs_synced) {
572	        for (const auto rfdc :
573	            {rfdc_control::rfdc_type::RX0, rfdc_control::rfdc_type::RX1}) {
574	            if (ncos_to_sync.count(rfdc)) {
575	                gearboxes_to_sync.insert(rfdc);
576	                // Technically, they're not synced yet but this saves us from
577	                // having to look up which RFDCs map to RX again later
578	                _adcs_synced = true;
579	            }
580	        }
581	    }
582	    if (!_dacs_synced) {
583	        for (const auto rfdc :
584	            {rfdc_control::rfdc_type::TX0, rfdc_control::rfdc_type::TX1}) {
585	            if (ncos_to_sync.count(rfdc)) {
586	                gearboxes_to_sync.insert(rfdc);
587	                // Technically, they're not synced yet but this saves us from
588	                // having to look up which RFDCs map to TX again later
589	                _dacs_synced = true;
590	            }
591	        }
592	    }
593	
594	    // ** Do synchronization **************************************************
595	    // This is where we orchestrate the sync commands. If sync commands happen
596	    // at different times, we make sure to send out the earlier one first.
597	    // If we need to schedule things a bit differently, e.g., we need to
598	    // manually calculate offsets from the command time so that LO and NCO sync
599	    // pulses line up, it most likely makes sense to use the scheduling expert
600	    // for that, and calculate different times for different events there.
601	    if (times_match) {
602	        UHD_LOG_TRACE(get_name(),
603	            "Syncing all channels: " << los_to_sync.size() << " LO(s), "
604	                                     << ncos_to_sync.size() << " NCO(s), and "
605	                                     << gearboxes_to_sync.size() << " gearbox(es).")
606	        if (!gearboxes_to_sync.empty()) {
607	            _rfdcc->reset_gearboxes(
608	                std::vector<rfdc_control::rfdc_type>(
609	                    gearboxes_to_sync.cbegin(), gearboxes_to_sync.cend()),
610	                _fe_time.at(0).get());
611	        }
612	        if (!los_to_sync.empty()) {
613	            _cpld->pulse_lo_sync(
614	                0, std::vector<zbx_lo_t>(los_to_sync.cbegin(), los_to_sync.cend()));
615	        }
616	        if (!ncos_to_sync.empty()) {
617	            _rfdcc->reset_ncos(std::vector<rfdc_control::rfdc_type>(
618	                                   ncos_to_sync.cbegin(), ncos_to_sync.cend()),
619	                _fe_time.at(0).get());
620	        }
621	    } else {
622	        // If the command times differ, we need to manually reorder the commands
623	        // such that the channel with the earlier time gets precedence
624	        const size_t first_sync_chan =
625	            (times_match || (_fe_time.at(0) <= _fe_time.at(1))) ? 0 : 1;
626	        const auto sync_order = (first_sync_chan == 0) ? std::vector<size_t>{0, 1}
627	                                                       : std::vector<size_t>{1, 0};
628	        for (const size_t chan : sync_order) {
629	            std::vector<zbx_lo_t> this_chan_los;
630	            for (const zbx_lo_t lo_idx : los[chan]) {
631	                if (los_to_sync.count(lo_idx)) {
632	                    this_chan_los.push_back(lo_idx);
633	                }
634	            }
635	
636	            std::vector<rfdc_control::rfdc_type> this_chan_ncos;
637	            for (const auto nco_idx : ncos[chan]) {
638	                if (ncos_to_sync.count(nco_idx)) {
639	                    this_chan_ncos.push_back(nco_idx);
640	                }
641	            }
642	            std::vector<rfdc_control::rfdc_type> this_chan_gearboxes;
643	            for (const auto gb_idx : ncos[chan]) {
644	                if (gearboxes_to_sync.count(gb_idx)) {
645	                    this_chan_gearboxes.push_back(gb_idx);
646	                }
647	            }
648	            UHD_LOG_TRACE(get_name(),
649	                "Syncing channel " << chan << ": " << this_chan_los.size()
650	                                   << " LO(s) and " << this_chan_ncos.size()
651	                                   << " NCO(s).");
652	            if (!this_chan_gearboxes.empty()) {
653	                UHD_LOG_TRACE(get_name(),
654	                    "Resetting " << this_chan_gearboxes.size() << " gearboxes.");
655	                _rfdcc->reset_gearboxes(this_chan_gearboxes, _fe_time.at(chan).get());
656	            }
657	            if (!this_chan_los.empty()) {
658	                _cpld->pulse_lo_sync(chan, this_chan_los);
659	            }
660	            if (!this_chan_ncos.empty()) {
661	                _rfdcc->reset_ncos(this_chan_ncos, _fe_time.at(chan).get());
662	            }
663	        }
664	    }
665	} // zbx_sync_expert::resolve()
666	
667	// End expert resolve sections
668	
669	}}} // namespace uhd::usrp::zbx
